snippet.async_client:
import asyncio

from seed import AsyncSeedApi
from seed.payment import (
    CreatePaymentRequestData,
    CreatePaymentRequestDataAttributes,
)

client = AsyncSeedApi(
    base_url="https://yourhost.com/path/to/api",
)


async def main() -> None:
    await client.payment.create_payment(
        data=CreatePaymentRequestData(
            type="payment",
            attributes=CreatePaymentRequestDataAttributes(
                amount=1,
                currency="currency",
            ),
        ),
    )


asyncio.run(main())
